+func TestScanNullTerminated(t *testing.T) {
+	t.Parallel()
+	tests := []struct {
+		name    string
+		data    []byte
+		atEOF   bool
+		advance int
+		token   []byte
+		wantNil bool
+	}{
+		{
+			name:    "empty at EOF",
+			data:    []byte{},
+			atEOF:   true,
+			advance: 0,
+			token:   nil,
+			wantNil: true,
+		},
+		{
+			name:    "single token with null",
+			data:    []byte("hello\x00"),
+			atEOF:   false,
+			advance: 6,
+			token:   []byte("hello"),
+		},
+		{
+			name:    "multiple tokens",
+			data:    []byte("first\x00second"),
+			atEOF:   false,
+			advance: 6,
+			token:   []byte("first"),
+		},
+		{
+			name:    "final token at EOF no null",
+			data:    []byte("final"),
+			atEOF:   true,
+			advance: 5,
+			token:   []byte("final"),
+		},
+		{
+			name:    "need more data",
+			data:    []byte("incomplete"),
+			atEOF:   false,
+			advance: 0,
+			token:   nil,
+			wantNil: true,
+		},
+		{
+			name:    "empty token",
+			data:    []byte("\x00rest"),
+			atEOF:   false,
+			advance: 1,
+			token:   []byte{},
+		},
+	}
+
+	for _, tt := range tests {
+		t.Run(tt.name, func(t *testing.T) {
+			advance, token, err := scanNullTerminated(tt.data, tt.atEOF)
+			if err != nil {
+				t.Errorf("unexpected error: %v", err)
+			}
+			if advance != tt.advance {
+				t.Errorf("advance = %d, want %d", advance, tt.advance)
+			}
+			if tt.wantNil {
+				if token != nil {
+					t.Errorf("token = %v, want nil", token)
+				}
+			} else {
+				if string(token) != string(tt.token) {
+					t.Errorf("token = %q, want %q", token, tt.token)
+				}
+			}
+		})
+	}
+}
